package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetHeaderWhenHeaderIsNull() {
        CSVFormat format = CSVFormat.DEFAULT.withHeader((String[]) null);
        assertNull(format.getHeader());
    }

    @Test
    void testGetHeaderReturnsCloneNotSameArray() {
        String[] headers = new String[] { "col1", "col2" };
        CSVFormat format = CSVFormat.DEFAULT.withHeader(headers);
        String[] returnedHeader = format.getHeader();
        assertArrayEquals(headers, returnedHeader);
        assertNotSame(headers, returnedHeader);
    }

    @Test
    void testGetHeaderWithEmptyHeader() {
        CSVFormat format = CSVFormat.DEFAULT.withHeader(new String[0]);
        String[] returnedHeader = format.getHeader();
        assertNotNull(returnedHeader);
        assertEquals(0, returnedHeader.length);
    }
}
